"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["4297"],{63195(e){e.exports=JSON.parse('{"tag":{"label":"Concepts","permalink":"/tags/concepts","allTagsPath":"/tags","count":67,"items":[{"id":"encyclopedia/temporal-sdks","title":"About Temporal SDKs","description":"Temporal SDKs are open-source tools enabling scalable and reliable application development. They feature APIs for Workflow and Activity execution, automatic retries, and resilience mechanisms, making it easier to build fault-tolerant applications.","permalink":"/encyclopedia/temporal-sdks"},{"id":"encyclopedia/activities/activity-definition","title":"Activity Definition","description":"Learn about defining Temporal Activities, including Activity Types, parameters, and implementation details.","permalink":"/activity-definition"},{"id":"encyclopedia/activities/activity-execution","title":"Activity Execution","description":"Understand how Activity Executions work in Temporal, including retries, timeouts, and failure handling.","permalink":"/activity-execution"},{"id":"encyclopedia/activities/activity-operations","title":"Activity Operations","description":"Operations you can perform on an Activity - Pause, Unpause, Reset, and Update Options.","permalink":"/activity-operations"},{"id":"encyclopedia/temporal-service/archival","title":"Archival","description":"Archival is a feature that automatically backs up Event Histories and Visibility records from Temporal Service persistence to a custom blob store.","permalink":"/temporal-service/archival"},{"id":"encyclopedia/child-workflows/child-workflows","title":"Child Workflows","description":"A Child Workflow Execution in the Temporal platform is initiated from another Workflow within the same Namespace.","permalink":"/child-workflows"},{"id":"encyclopedia/data-conversion/codec-server","title":"Codec Server","description":"A Codec Server is an HTTP server that provides remote encoding and decoding for Temporal Payloads.","permalink":"/codec-server"},{"id":"encyclopedia/context-propagation","title":"Context Propagation","description":"Pass custom key-value data across Workflow, Activity, and Child Workflow boundaries using Temporal headers.","permalink":"/encyclopedia/context-propagation"},{"id":"encyclopedia/workflow/workflow-execution/continue-as-new","title":"Continue-As-New","description":"Continue-As-New is a mechanism by which the latest relevant state is passed to a new Workflow Execution, with a fresh Event History.","permalink":"/workflow-execution/continue-as-new"},{"id":"encyclopedia/data-conversion/default-custom-data-converters","title":"Default and Custom Data Converters","description":"Learn about the default Data Converter in Temporal SDKs and how to implement a custom Data Converter for custom serialization and encoding needs.","permalink":"/default-custom-data-converters"},{"id":"encyclopedia/detecting-activity-failures","title":"Detecting Activity failures","description":"Understand Activity Execution timeouts in Temporal; Schedule-To-Start, Start-To-Close, Schedule-To-Close, and Activity Heartbeats, for effective Workflow management.","permalink":"/encyclopedia/detecting-activity-failures"},{"id":"encyclopedia/detecting-application-failures","title":"Detecting application failures","description":"In Temporal, timeouts detect and mitigate Workflow and Activity failures with automatic retries using configurable timeout settings and customizable RetryPolicies.","permalink":"/encyclopedia/detecting-application-failures"},{"id":"encyclopedia/detecting-workflow-failures","title":"Detecting Workflow failures","description":"Learn about Workflow Execution Timeout, Workflow Run Timeout, and Workflow Task Timeout in Temporal. Maximize Workflow efficiency and manage durations effectively.","permalink":"/encyclopedia/detecting-workflow-failures"},{"id":"encyclopedia/visibility/dual-visibility","title":"Dual Visibility","description":"This guide on Temporal Dual Visibility explains how to set up, configure, and use Dual Visibility in Temporal Server versions. Learn about configuring primary and secondary Visibility stores, migrating databases, and ensuring a smooth transition for Visibility data.","permalink":"/dual-visibility"},{"id":"encyclopedia/workflow/dynamic-handler","title":"Dynamic handler","description":"Dynamic Handlers can serve as fallback mechanisms for handling Workflows, Activities, Signals, Queries, or Updates that aren\'t registered by name.","permalink":"/dynamic-handler"},{"id":"encyclopedia/workflow/workflow-execution/event","title":"Events and Event History","description":"Events are created by the Temporal Service in response to external occurrences and Commands generated by a Workflow Execution.","permalink":"/workflow-execution/event"},{"id":"encyclopedia/extensibility","title":"Extensibility","description":"Temporal offers mechanisms to augment the functionality of Workflows and Activities, including data conversion, context propagation, interceptors, and plugins.","permalink":"/encyclopedia/extensibility"},{"id":"encyclopedia/data-conversion/failure-converter","title":"Failure Converter","description":"A Failure Converter transforms error messages and call stacks into encoded formats to enhance security and observability.","permalink":"/failure-converter"},{"id":"encyclopedia/namespaces/global-namespaces","title":"Global Namespace","description":"This guide covers everything about Global Namespaces within the Temporal Platform.","permalink":"/global-namespace"},{"id":"encyclopedia/workflow-message-passing/handling-messages","title":"Handling Signals, Queries, & Updates","description":"Signals, Queries, and Updates facilitate interactions with Workflow Executions.","permalink":"/handling-messages"},{"id":"encyclopedia/data-conversion/dataconversion","title":"How does Temporal handle application data?","description":"This guide explores Data Converters in the Temporal Platform, detailing how they handle serialization and encoding for Workflow inputs and outputs, ensuring data stays secure and manageable.","permalink":"/dataconversion"},{"id":"encyclopedia/interceptors","title":"Interceptors","description":"Add cross-cutting behavior like observability, authorization, and header manipulation before and after SDK operations.","permalink":"/encyclopedia/interceptors"},{"id":"encyclopedia/data-conversion/key-management","title":"Key management","description":"Learn about key management practices for securing encryption keys in Temporal applications.","permalink":"/key-management"},{"id":"encyclopedia/visibility/list-filter","title":"List Filter","description":"This guide on Temporal List Filters explains how to set up, configure, and use the List Filter API in Temporal Server versions. Filter and retrieve Workflow Executions, apply supported operators, and optimize queries for efficiency.","permalink":"/list-filter"},{"id":"encyclopedia/activities/local-activity","title":"Local Activity","description":"Learn about Local Activities in Temporal, their benefits, execution model, and when to use them.","permalink":"/local-activity"},{"id":"encyclopedia/temporal-service/multi-cluster-replication","title":"Multi-Cluster Replication","description":"Multi-Cluster Replication is a feature which asynchronously replicates Workflow Executions from active Clusters to other passive Clusters, for backup and state reconstruction.","permalink":"/temporal-service/multi-cluster-replication"},{"id":"cloud/get-started/namespaces","title":"Namespaces","description":"A Namespace is a unit of isolation within Temporal Cloud, providing security boundaries, Workflow management, unique identifiers, and gRPC endpoints in Temporal Cloud.","permalink":"/cloud/namespaces"},{"id":"encyclopedia/nexus/nexus-endpoints","title":"Nexus Endpoints","description":"Nexus Endpoints are reverse proxies that connect Nexus callers and handlers forwarding Nexus requests to an upstream target Namespace and Task Queue that a Worker is polling.","permalink":"/nexus/endpoints"},{"id":"encyclopedia/nexus/nexus-operations","title":"Nexus Operations","description":"Learn about the Nexus Operation lifecycle, execution semantics, and automatic retries for reliable execution.","permalink":"/nexus/operations"},{"id":"encyclopedia/nexus/nexus-patterns","title":"Nexus Patterns","description":"Common patterns for building Nexus Services including the collocated pattern and the router-queue pattern for flexible deployment topologies.","permalink":"/nexus/patterns"},{"id":"encyclopedia/nexus/nexus-registry","title":"Nexus Registry","description":"Use the Nexus Registry to manage Nexus Endpoints.","permalink":"/nexus/registry"},{"id":"encyclopedia/nexus/nexus-services","title":"Nexus services","description":"Nexus Services are named collections of arbitrary-duration Nexus Operations that provide a microservice contract suitable for sharing across team boundaries.","permalink":"/nexus/services"},{"id":"encyclopedia/child-workflows/parent-close-policy","title":"Parent Close Policy","description":"Understand the Parent-Child Workflow relationship, including when to use Child Workflows and Parent Close Policies.","permalink":"/parent-close-policy"},{"id":"encyclopedia/data-conversion/payload-codec","title":"Payload Codec","description":"A Payload Codec performs bytes-to-bytes transformations on Temporal Payloads, often for compression and encryption.","permalink":"/payload-codec"},{"id":"encyclopedia/data-conversion/payload-converter","title":"Payload Converter","description":"A Payload Converter serializes and deserializes values to and from bytes for use in the Temporal SDK.","permalink":"/payload-converter"},{"id":"encyclopedia/temporal-service/persistence","title":"Persistence","description":"The Temporal Persistence store is a database used by the Temporal Server to persist events generated and processed in your Temporal Service and SDK.","permalink":"/temporal-service/persistence"},{"id":"encyclopedia/plugins","title":"Plugins","description":"Bundle interceptors, context propagators, data converters, and built-in definitions into reusable packages.","permalink":"/encyclopedia/plugins"},{"id":"encyclopedia/data-conversion/remote-data-encoding","title":"Remote data encoding","description":"Use remote encoding to transform data for the Temporal CLI and Web UI.","permalink":"/remote-data-encoding"},{"id":"encyclopedia/workflow/workflow-schedule","title":"Schedule","description":"A Schedule contains instructions for starting a Workflow Execution at specific times. Schedules provide a more flexible and user-friendly approach than Temporal Cron Jobs.","permalink":"/schedule"},{"id":"encyclopedia/visibility/search-attribute","title":"Search Attributes","description":"This guide on Temporal Search Attributes explains how to set up, configure, and use default and custom Search Attributes in Temporal Server versions. Learn about supported types, limits, and how to use them to enhance Workflow filtering and querying.","permalink":"/search-attribute"},{"id":"encyclopedia/nexus/nexus-security","title":"Security in Temporal Nexus","description":"Explore the security aspects of Temporal Nexus, including managing Nexus Endpoints, runtime access control, secure routing, and payload encryption to ensure safe and reliable cross-namespace operations.","permalink":"/nexus/security"},{"id":"encyclopedia/workflow-message-passing/sending-messages","title":"Sending Signals, Queries, & Updates","description":"Signals, Queries, and Updates facilitate interactions with Workflow Executions.","permalink":"/sending-messages"},{"id":"encyclopedia/activities/standalone-activity","title":"Standalone Activity","description":"Learn about Standalone Activities in Temporal, their benefits, execution model, and when to use them.","permalink":"/standalone-activity"},{"id":"encyclopedia/workers/tasks","title":"Tasks","description":"Learn about the types of Tasks in Temporal and their role in Workflow and Activity Executions.","permalink":"/tasks"},{"id":"encyclopedia/workflow/cron-job","title":"Temporal Cron Job","description":"A Temporal Cron Job is the series of Workflow Executions that occur when a Cron Schedule is provided in the call to spawn a Workflow Execution.","permalink":"/cron-job"},{"id":"develop/go/go-sdk-multithreading","title":"Temporal Go SDK multithreading","description":"The Temporal Go SDK ensures deterministic multithreading in Workflows using workflow.Go(), avoiding race conditions and eliminating the need for mutexes.","permalink":"/develop/go/go-sdk-multithreading"},{"id":"encyclopedia/namespaces/namespaces","title":"Temporal Namespace","description":"A Namespace is a unit of isolation within the Temporal Platform that provides resource separation, Workflow ID uniqueness, and configuration boundaries.","permalink":"/namespaces"},{"id":"encyclopedia/nexus/nexus","title":"Temporal Nexus","description":"Temporal Nexus connects Temporal Applications across isolated Namespaces with clean service contracts, built-in durability, observability, and security.","permalink":"/nexus"},{"id":"develop/python/python-sdk-sandbox","title":"Temporal Python SDK sandbox environment","description":"The Temporal Python SDK offers a sandbox environment to run Workflow code, aiming to prevent non-determinism errors in applications by isolating global state and applying restrictions.","permalink":"/develop/python/python-sdk-sandbox"},{"id":"develop/python/python-sdk-sync-vs-async","title":"Temporal Python SDK synchronous vs. asynchronous Activity implementations","description":"The Temporal Python SDK supports implementing Activities asynchronously with asyncio, synchronously with ThreadPoolExecutor or ProcessPoolExecutor. Choose the correct method to avoid application errors.","permalink":"/develop/python/python-sdk-sync-vs-async"},{"id":"encyclopedia/temporal-service/temporal-server","title":"Temporal Server","description":"The Temporal Server consists of four independently scalable services - Frontend gateway, History subsystem, Matching subsystem, and Worker Service.","permalink":"/temporal-service/temporal-server"},{"id":"encyclopedia/temporal-service/temporal-service","title":"Temporal Service","description":"This page provides a comprehensive technical overview of a Temporal Service, detailing its components and subsystems, including the Temporal Server, Frontend Service, History Service, Matching Service, and Worker Service.","permalink":"/temporal-service"},{"id":"encyclopedia/temporal-service/temporal-service-configuration","title":"Temporal Service configuration","description":"Temporal Service configuration is the setup and configuration details of your self-hosted Temporal Service, defined using YAML.","permalink":"/temporal-service/configuration"},{"id":"encyclopedia/visibility/visibility","title":"Temporal Visibility","description":"Temporal Visibility enables operators to view, filter, and search Workflow Executions using List Filters and Search Attributes. Learn about supported databases, Dual Visibility, and custom Search Attributes.","permalink":"/visibility"},{"id":"encyclopedia/workflow/workflow-overview","title":"Temporal Workflow","description":"This comprehensive guide provides insights into Temporal Workflows, covering Workflow Definitions in various programming languages, deterministic constraints, handling code changes, and ensuring reliability, durability, and scalability in a Temporal Application, with examples and best practices for Workflow Versioning and development.","permalink":"/workflows"},{"id":"encyclopedia/workflow/workflow-definition","title":"Temporal Workflow Definition","description":"A Workflow Definition in Temporal is the code that defines the constraints of a Workflow Execution.","permalink":"/workflow-definition"},{"id":"encyclopedia/workflow/workflow-execution/workflow-execution","title":"Temporal Workflow Execution overview","description":"A Temporal Workflow Execution is a durable, reliable, and scalable function execution and the main unit of execution of a Temporal Application.","permalink":"/workflow-execution"},{"id":"encyclopedia/workflow-message-passing/workflow-message-passing","title":"Temporal Workflow message passing - Signals, Queries, & Updates","description":"Signals, Queries, and Updates facilitate interactions with Workflow Executions.","permalink":"/encyclopedia/workflow-message-passing/"},{"id":"encyclopedia/workflow/workflow-execution/timers-delays","title":"Timers and Start Delays","description":"Temporal SDKs offer Timer APIs so that Workflow Executions are deterministic in their handling of time values.","permalink":"/workflow-execution/timers-delays"},{"id":"encyclopedia/temporal-service/visibility","title":"Visibility","description":"The term Visibility, within the Temporal Platform, refers to the subsystems and APIs that enable an operator to view, filter, and search for Workflow Executions that currently exist within a Temporal Service.","permalink":"/temporal-service/visibility"},{"id":"encyclopedia/activities/activities","title":"What is a Temporal Activity?","description":"Understand Temporal Activities, including  Activity Definitions, Types, Executions, idempotency, cancellations, Local Activities, and Standalone Activities.","permalink":"/activities"},{"id":"encyclopedia/retry-policies","title":"What is a Temporal Retry Policy?","description":"Optimize your Workflow and Activity Task Executions with a custom Retry Policy on Temporal. Understand default retries, intervals, backoff, and maximum attempts for error handling.","permalink":"/encyclopedia/retry-policies"},{"id":"encyclopedia/workers/workers","title":"What is a Temporal Worker?","description":"Temporal Workers are tightly coupled with Task Queues and Worker Processes.","permalink":"/workers"},{"id":"encyclopedia/temporal","title":"What is Temporal?","description":"Temporal is a scalable platform that ensures the Durable Execution of application code, allowing reliable and resilient Workflow Executions even in the face of failures like network outages or server crashes.","permalink":"/temporal"},{"id":"encyclopedia/worker-versioning-legacy","title":"Worker versioning (legacy)","description":"Remember how to use the now-deprecated pre-release version of Worker Versioning","permalink":"/encyclopedia/worker-versioning-legacy"},{"id":"encyclopedia/workflow/workflow-execution/limits","title":"Workflow Execution limits","description":"The Workflow Execution\'s Event History is limited to 51,200 Events or 50 MB and will warn you after 10,240 Events or 10 MB.","permalink":"/workflow-execution/limits"},{"id":"encyclopedia/workflow/workflow-execution/workflowid-runid","title":"Workflow Id and Run Id","description":"A Workflow Id is a customizable, application-level identifier for a Workflow Execution that is unique to an Open Workflow Execution within a Namespace.","permalink":"/workflow-execution/workflowid-runid"}],"unlisted":false}}')}}]);